import React, { useState } from 'react';
import AssetTreePanel from './AssetTreePanel';
import AssetToolbar from './AssetToolbar';
import AssetTable from './AssetTable';

const assetCategories = [
  'Access Point',
  'Computers',
  'Keyboard',
  'Mobile',
  'Mobile Phone',
  'Printer',
  'Projector',
  'Router',
  'Scanner',
  'Switch',
  'Blank Plastic Cards',
  'Cable Tie',
  'Chairs',
  'Cleaning Sheets',
  'Cooling Pad',
  'Fax Paper Roll',
  'HDMI Cable',
  'Inkjet Cartridge',
  'Laptop Bag',
  'Laptop RAM DDR 4',
  'Laptop Stickers',
  'Motherboard Battery',
  'Mouse Pad',
  'Network Cable',
  'Printer Ribbon for Plastic Cards',
  'Ribbon',
  'Sleeve',
  'Software',
];

const AssetsPage: React.FC = () => {
  const [selectedCategory, setSelectedCategory] = useState<string>('All Assets');
  const [selectedRows, setSelectedRows] = useState<string[]>([]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <div className="text-sm uppercase tracking-[0.24em] text-slate-500">Assets</div>
          <h1 className="mt-2 text-3xl font-semibold text-slate-900">All Assets</h1>
        </div>
      </div>

      <div className="grid gap-6 xl:grid-cols-[250px_minmax(0,1fr)]">
        <AssetTreePanel
          categories={assetCategories}
          selectedCategory={selectedCategory}
          onSelectCategory={setSelectedCategory}
        />

        <div className="space-y-5">
          <AssetToolbar
            selectedCount={selectedRows.length}
            onAddNew={() => {
              // placeholder for Add new action
            }}
            onDeleteSelected={() => {
              setSelectedRows([]);
            }}
            onClearFilters={() => {
              setSelectedCategory('All Assets');
            }}
            onSelectColumns={() => {
              // placeholder for Select Columns action
            }}
          />

          <AssetTable selectedRows={selectedRows} onSelectedRowsChange={setSelectedRows} />
        </div>
      </div>
    </div>
  );
};

export default AssetsPage;
